-- =============================================================
-- Consulta original (baseline) — antes do tuning
-- avel.activities — atividades concluídas no dia, por lista de usuários.
-- Duas versões coladas (mesma forma; lista grande vs. um único user_id).
-- =============================================================

-- (A) lista de ~42 usuários
SELECT `avel`.`activities`.`id`, `avel`.`activities`.`activitie_id`, `avel`.`activities`.`deal_id`, `avel`.`activities`.`owner_name`, `avel`.`activities`.`done_time`, `avel`.`activities`.`activitie_type`, `avel`.`activities`.`created_by_user_id`, `avel`.`activities`.`add_time`, `avel`.`activities`.`user_id`, `avel`.`activities`.`update_user_id`, `avel`.`activities`.`name`, `avel`.`activities`.`update_time`, `avel`.`activities`.`att_date`, `avel`.`activities`.`intensity_points`, `avel`.`activities`.`is_deleted`, `avel`.`activities`.`is_recorded`, `avel`.`activities`.`activity_detail`, `avel`.`activities`.`schedule_time` FROM `avel`.`activities` WHERE (`avel`.`activities`.`user_id` IN (22226784,24390583,16596360,23605590,16506124,23479090,20948408,24002481,23479101,24266767,22043337,24390616,24390627,17112524,20948430,24131478,23332856,24390638,22043216,22952949,24390649,12608615,21777335,23332878,22757325,22226806,22595119,20948397,22413124,22595218,9940043,23605601,22952685,22413146,22226817,22757369,12424402,23874925,24893481,15463712,21384910,22952729) AND `avel`.`activities`.`done_time` >= '2026-06-09 00:00:00' AND `avel`.`activities`.`done_time` <= '2026-06-09 23:59:59.999000' AND `avel`.`activities`.`is_deleted` = 0) ORDER BY `avel`.`activities`.`done_time` DESC;

-- (B) um único user_id (mesma forma)
SELECT `avel`.`activities`.`id`, `avel`.`activities`.`activitie_id`, `avel`.`activities`.`deal_id`, `avel`.`activities`.`owner_name`, `avel`.`activities`.`done_time`, `avel`.`activities`.`activitie_type`, `avel`.`activities`.`created_by_user_id`, `avel`.`activities`.`add_time`, `avel`.`activities`.`user_id`, `avel`.`activities`.`update_user_id`, `avel`.`activities`.`name`, `avel`.`activities`.`update_time`, `avel`.`activities`.`att_date`, `avel`.`activities`.`intensity_points`, `avel`.`activities`.`is_deleted`, `avel`.`activities`.`is_recorded`, `avel`.`activities`.`activity_detail`, `avel`.`activities`.`schedule_time` FROM `avel`.`activities` WHERE (`avel`.`activities`.`user_id` IN (24705122) AND `avel`.`activities`.`done_time` >= '2026-06-09 00:00:00' AND `avel`.`activities`.`done_time` <= '2026-06-09 23:59:59.999000' AND `avel`.`activities`.`is_deleted` = 0) ORDER BY `avel`.`activities`.`done_time` DESC;
